package dev.wrkflw.domain.identity

import java.util.UUID

@JvmInline
value class ActorId(val value: String)

@JvmInline
value class GroupId(val value: String)

@JvmInline
value class FlowDefinitionKey(val value: String)

@JvmInline
value class FlowInstanceId(val value: UUID) {
    companion object {
        fun generate(): FlowInstanceId = FlowInstanceId(UUID.randomUUID())
    }
}

@JvmInline
value class TaskId(val value: UUID) {
    companion object {
        fun generate(): TaskId = TaskId(UUID.randomUUID())
    }
}

package dev.wrkflw.domain.flow

import dev.wrkflw.domain.identity.GroupId

enum class StateType {
    HUMAN_TASK,
    TERMINAL
}

enum class Trigger {
    APPROVE,
    REJECT,
    SUBMIT
}

data class StateDefinition(
    val name: String,
    val type: StateType,
    val candidateGroupId: GroupId? = null,
    val terminalOutcome: String? = null
) {
    init {
        require(name.isNotBlank()) { "State name must not be blank" }
        if (type == StateType.HUMAN_TASK) {
            require(candidateGroupId != null) { "HUMAN_TASK state must have a candidateGroupId" }
        }
        if (type == StateType.TERMINAL) {
            require(terminalOutcome != null) { "TERMINAL state must have a terminalOutcome" }
        }
    }
}

data class TransitionDefinition(
    val from: String,
    val trigger: Trigger,
    val to: String,
    val guard: String? = null
) {
    init {
        require(from.isNotBlank()) { "Transition 'from' must not be blank" }
        require(to.isNotBlank()) { "Transition 'to' must not be blank" }
    }
}

data class FlowDefinition(
    val key: FlowDefinitionKey,
    val version: Int,
    val initialState: String,
    val initiatorGroupId: GroupId,
    val states: List<StateDefinition>,
    val transitions: List<TransitionDefinition>
) {
    init {
        require(version >= 1) { "Version must be >= 1" }
        require(states.isNotEmpty()) { "Must have at least one state" }
        require(transitions.isNotEmpty()) { "Must have at least one transition" }

        val stateNames = states.map { it.name }.toSet()
        require(stateNames.contains(initialState)) {
            "Initial state '$initialState' not found in states: $stateNames"
        }

        val terminalStates = states.filter { it.type == StateType.TERMINAL }
        require(terminalStates.isNotEmpty()) { "Must have at least one terminal state" }

        for (transition in transitions) {
            require(stateNames.contains(transition.from)) {
                "Transition from '${transition.from}' references unknown state"
            }
            require(stateNames.contains(transition.to)) {
                "Transition to '${transition.to}' references unknown state"
            }
        }

        for (state in states) {
            if (state.type == StateType.TERMINAL) {
                require(transitions.none { it.from == state.name }) {
                    "Terminal state '${state.name}' must not have outgoing transitions"
                }
            }
        }
    }

    fun isTerminal(stateName: String): Boolean =
        states.find { it.name == stateName }?.type == StateType.TERMINAL

    fun terminalOutcome(stateName: String): String? =
        states.find { it.name == stateName }?.terminalOutcome

    fun candidateGroup(stateName: String): GroupId? =
        states.find { it.name == stateName }?.candidateGroupId
}

package dev.wrkflw.domain.flow

data class FlowInterpreterResult(
    val nextState: String?,
    val terminalOutcome: String?,
    val isTerminal: Boolean
) {
    companion object {
        fun advance(stateName: String, trigger: Trigger, definition: FlowDefinition): FlowInterpreterResult {
            val transition = definition.transitions.find {
                it.from == stateName && it.trigger == trigger
            }

            if (transition == null) {
                throw InvalidTransitionException(
                    "No transition from '$stateName' with trigger $trigger in definition ${definition.key.value}"
                )
            }

            val isTerminal = definition.isTerminal(transition.to)
            return FlowInterpreterResult(
                nextState = if (isTerminal) null else transition.to,
                terminalOutcome = if (isTerminal) definition.terminalOutcome(transition.to) else null,
                isTerminal = isTerminal
            )
        }

        fun initialState(definition: FlowDefinition): String = definition.initialState
    }
}

class InvalidTransitionException(message: String) : IllegalStateException(message)

package dev.wrkflw.domain.task

import dev.wrkflw.domain.identity.ActorId
import dev.wrkflw.domain.identity.GroupId
import dev.wrkflw.domain.identity.TaskId
import java.time.Instant

enum class TaskStatus {
    PENDING,
    CLAIMED,
    COMPLETED
}

enum class DecisionOutcome {
    APPROVE,
    REJECT
}

data class Decision(
    val taskId: TaskId,
    val outcome: DecisionOutcome,
    val actorId: ActorId,
    val comment: String?,
    val decidedAt: Instant
)

data class Task(
    val id: TaskId,
    val flowInstanceId: dev.wrkflw.domain.identity.FlowInstanceId,
    val stateName: String,
    val candidateGroupId: GroupId,
    val status: TaskStatus,
    val ownerId: ActorId? = null,
    val version: Int = 0,
    val createdAt: Instant,
    val claimedAt: Instant? = null,
    val completedAt: Instant? = null
) {
    companion object {
        fun create(
            flowInstanceId: dev.wrkflw.domain.identity.FlowInstanceId,
            stateName: String,
            candidateGroupId: GroupId,
            now: Instant
        ): Task = Task(
            id = TaskId.generate(),
            flowInstanceId = flowInstanceId,
            stateName = stateName,
            candidateGroupId = candidateGroupId,
            status = TaskStatus.PENDING,
            createdAt = now
        )
    }

    fun claim(actorId: ActorId, now: Instant): Task {
        require(status == TaskStatus.PENDING) { "Task must be PENDING to claim, was $status" }
        return copy(
            status = TaskStatus.CLAIMED,
            ownerId = actorId,
            claimedAt = now,
            version = version + 1
        )
    }

    fun release(actorId: ActorId, now: Instant): Task {
        require(status == TaskStatus.CLAIMED) { "Task must be CLAIMED to release, was $status" }
        require(ownerId == actorId) { "Only the owner can release this task" }
        return copy(
            status = TaskStatus.PENDING,
            ownerId = null,
            claimedAt = null,
            version = version + 1
        )
    }

    fun completeDecision(
        outcome: DecisionOutcome,
        actorId: ActorId,
        comment: String?,
        now: Instant
    ): Pair<Task, Decision> {
        require(status == TaskStatus.CLAIMED) { "Task must be CLAIMED to decide, was $status" }
        require(ownerId == actorId) { "Only the owner can decide on this task" }

        val decision = Decision(
            taskId = id,
            outcome = outcome,
            actorId = actorId,
            comment = comment,
            decidedAt = now
        )

        val completedTask = copy(
            status = TaskStatus.COMPLETED,
            completedAt = now,
            version = version + 1
        )

        return completedTask to decision
    }
}

