package dev.wrkflw

import dev.wrkflw.domain.di.domainModule
import dev.wrkflw.eventing.di.eventingModule
import dev.wrkflw.persistence.di.persistenceModule
import dev.wrkflw.rest.di.restApiModule
import dev.wrkflw.temporal.di.temporalModule
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import io.ktor.server.application.*
