package dev.wrkflw.persistence

import org.jooq.DSLContext
import org.jooq.impl.DSL

object TransactionRunner {
    inline fun <T> run(dslContext: DSLContext, crossinline block: (DSLContext) -> T): T {
        return dslContext.transactionResult { config ->
            block(DSL.using(config))
        }
    }
}

